224→      if (!interval) return null;
225→
226→      const startProjection = projectPointToSectionCut(sectionCut, renderData.startPoint);
227→      const endProjection = projectPointToSectionCut(sectionCut, renderData.endPoint);
228→      const clampedStart = clamp(startProjection.along, 0, sectionCutLength(sectionCut));
229→      const clampedEnd = clamp(endProjection.along, 0, sectionCutLength(sectionCut));
230→      if (Math.abs(clampedEnd - clampedStart) < EPSILON) return null;
231→
232→      const risers = Math.max(1, stair.numberOfRisers || 1);
233→      const rise = stairTotalRise(stair);
234→      const risePerRiser = rise / risers;
235→      const alongStep = (clampedEnd - clampedStart) / risers;
236→      const points = [{ x: clampedStart, z: floor.level ?? 0 }];
237→      let currentAlong = clampedStart;
238→      let currentZ = floor.level ?? 0;
239→
240→      for (let index = 0; index < risers; index += 1) {
241→        currentAlong += alongStep;
242→        points.push({ x: currentAlong, z: currentZ });
243→        currentZ += risePerRiser;
244→        points.push({ x: currentAlong, z: currentZ });
245→      }
246→
247→      return {
248→        id: `section-stair-${stair.id}`,
249→        category: 'stair',
250→        renderMode: cutInterval ? 'cut' : 'projection',
251→        points,
252→        depth: projection?.depth ?? 0,
253→        sourceId: stair.id,
254→      };
255→    })
256→    .filter(Boolean);
