  // Hit test columns
  for (const sc of (floor.sectionCuts || [])) {
    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
      return { id: sc.id, type: 'sectionCut' };
    }
  }

  for (const column of (floor.columns || [])) {
    const outline = columnOutline(column);
    if (pointInPolygon(modelPos, outline)) {
      return { id: column.id, type: 'column' };
    }
  }

  // Hit test beams
  for (const beam of (floor.beams || [])) {
    const renderData = getBeamRenderData(beam, floor.columns || []);
    if (!renderData) continue;
    if (pointInPolygon(modelPos, renderData.outline)) {
      return { id: beam.id, type: 'beam' };
    }
  }

  // Hit test walls
  for (const wall of floor.walls) {
    const outline = getWallRenderData(wall, floor.columns || []).outline;
    if (pointInPolygon(modelPos, outline)) {
      return { id: wall.id, type: 'wall' };
    }
  }

  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
  for (const stair of (floor.stairs || [])) {
    const renderData = getStairRenderData(stair);
    if (!renderData) continue;
    if (pointInPolygon(modelPos, renderData.outline)) {
      return { id: stair.id, type: 'stair' };
    }
  }

  // Hit test rooms (lowest priority)
  for (const room of floor.rooms) {
    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
      return { id: room.id, type: 'room' };
    }
  }

  if (floor.slab && slabContainsPoint(floor.slab, modelPos)) {
    return { id: floor.slab.id, type: 'slab' };
  }

  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
  if (annotationHit) {
    return annotationHit;
  }

  return null;
}

export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
  return {
    onMouseDown(modelPos, e, toolState) {
      if (e.button !== 0) return;

      const floor = getFloor(activeFloorId);
      if (!floor) return;

      // Check if clicking a handle
      const target = e.target;
      if (target.dataset.handle) {
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: {
            dragging: true,
            dragType: 'handle',
            handle: target.dataset.handle,
            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
            startPos: modelPos,
          },
        });
        return;
      }

      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
      if (hit) {
        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
        const draggableTypes = new Set(['wall', 'column', 'door', 'window', 'stair', 'sectionCut']);
        if (!draggableTypes.has(hit.type)) return;
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: {
            dragging: true,
            dragType: 'move',
            startPos: modelPos,
            originalPos: modelPos,
          },
        });
      } else {
        editorDispatch({ type: 'DESELECT' });
      }
    },

    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
      if (!toolState.dragging || !selectedId) return;

      const floor = getFloor(activeFloorId);
      if (!floor) return;
      const dx = modelPos.x - toolState.startPos.x;
      const dy = modelPos.y - toolState.startPos.y;
      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;

      if (selectedType === 'wall') {
        const wall = floor.walls.find(w => w.id === selectedId);
        if (!wall) return;
        const resolved = resolveWallEndpoints(wall, floor.columns || []);

        if (toolState.dragType === 'handle') {
          const handle = toolState.handle;
          const oppositeKey = handle === 'start' ? 'end' : 'start';
          const oppositePoint = resolved[oppositeKey];
          let nextPoint = modelPos;
          let nextAttachment = null;

          if (e.shiftKey) {
            const dx = modelPos.x - oppositePoint.x;
            const dy = modelPos.y - oppositePoint.y;
            const angle = Math.atan2(dy, dx);
            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
            const len = Math.sqrt(dx * dx + dy * dy);
            nextPoint = {
              x: oppositePoint.x + Math.cos(snapAngle) * len,
              y: oppositePoint.y + Math.sin(snapAngle) * len,
            };
          } else if (snapEnabled) {
            const snapResult = snapWallEndpoint(modelPos, {
              walls: floor.walls,
              columns: floor.columns || [],
              snapDist: snapDistModel,
              otherPoint: oppositePoint,
              ignoreWallId: wall.id,
            });
            if (snapResult) {
              nextPoint = snapResult.point;
              nextAttachment = snapResult.attachment;
            }
          }

          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;

          dispatch({
            type: 'WALL_UPDATE',
            floorId: activeFloorId,
            wall: {
              id: wall.id,
              [handle]: nextPoint,
              [`${handle}Attachment`]: nextAttachment,
            },
          });
        } else {
          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
          let startAttachment = null;
          let endAttachment = null;

          if (snapEnabled) {
            const startSnap = snapWallEndpoint(nextStart, {
              walls: floor.walls,
              columns: floor.columns || [],
              snapDist: snapDistModel,
              otherPoint: nextEnd,
              ignoreWallId: wall.id,
            });
            if (startSnap) {
              nextStart = startSnap.point;
              startAttachment = startSnap.attachment;
            }

            const endSnap = snapWallEndpoint(nextEnd, {
              walls: floor.walls,
              columns: floor.columns || [],
              snapDist: snapDistModel,
              otherPoint: nextStart,
              ignoreWallId: wall.id,
            });
            if (endSnap) {
              nextEnd = endSnap.point;
              endAttachment = endSnap.attachment;
            }
          }

          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;

          dispatch({
            type: 'WALL_UPDATE',
            floorId: activeFloorId,
            wall: {
              id: wall.id,
              start: nextStart,
              end: nextEnd,
              startAttachment,
              endAttachment,
            },
          });
        }
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { startPos: modelPos },
        });
      } else if (selectedType === 'column') {
        const col = (floor.columns || []).find(c => c.id === selectedId);
        if (!col) return;
        dispatch({
          type: 'COLUMN_UPDATE',
          floorId: activeFloorId,
          column: { id: col.id, x: col.x + dx, y: col.y + dy },
        });
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { startPos: modelPos },
        });
      } else if (selectedType === 'sectionCut') {
        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
        if (!sectionCut) return;

        if (toolState.dragType === 'handle') {
          const handle = toolState.handle;
          const nextSectionCut = handle === 'start'
            ? { ...sectionCut, startPoint: modelPos }
            : { ...sectionCut, endPoint: modelPos };

          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;

          dispatch({
            type: 'SECTION_UPDATE',
            floorId: activeFloorId,
            sectionCut: nextSectionCut,
          });
        } else {
          dispatch({
            type: 'SECTION_UPDATE',
            floorId: activeFloorId,
            sectionCut: {
              id: sectionCut.id,
              startPoint: {
                x: sectionCut.startPoint.x + dx,
                y: sectionCut.startPoint.y + dy,
              },
              endPoint: {
                x: sectionCut.endPoint.x + dx,
                y: sectionCut.endPoint.y + dy,
              },
            },
          });
          editorDispatch({
            type: 'UPDATE_TOOL_STATE',
            payload: { startPos: modelPos },
          });
        }
      } else if (selectedType === 'beam') {
        return;
      } else if (selectedType === 'stair') {
        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
        if (!stair) return;
        dispatch({
          type: 'STAIR_UPDATE',
          floorId: activeFloorId,
          stair: {
            id: stair.id,
            startPoint: {
              x: stair.startPoint.x + dx,
              y: stair.startPoint.y + dy,
            },
          },
        });
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { startPos: modelPos },
        });
      } else if (selectedType === 'slab') {
        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
          return;
        }
        if (!floor.slab || floor.slab.id !== selectedId) return;

        const boundaryPoints = floor.slab.boundaryPoints.map((point, index) => (
          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
        ));

        dispatch({
          type: 'SLAB_UPDATE',
          floorId: activeFloorId,
          slab: {
            id: floor.slab.id,
            boundaryPoints,
          },
        });
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { startPos: modelPos },
        });
      } else if (selectedType === 'door' || selectedType === 'window') {
        // Slide along parent wall
        const items = selectedType === 'door' ? floor.doors : floor.windows;
        const item = items.find(i => i.id === selectedId);
        if (!item) return;

        const wall = floor.walls.find(w => w.id === item.wallId);
        if (!wall) return;

        const newOffset = projectPointOnWall(wall, modelPos);
        const halfWidth = item.width / 2;
        const maxOffset = wallLength(wall) - halfWidth;
        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));

        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
        dispatch({
          type: updateType,
          floorId: activeFloorId,
          [selectedType]: { id: item.id, offset: clampedOffset },
        });

        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { startPos: modelPos },
        });
      }
    },

    onMouseUp(modelPos, e, toolState) {
      if (toolState.dragging) {
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { dragging: false, dragType: null, handle: null, handleIndex: null },
        });
      }
    },

    onKeyDown(e, toolState, selectedId, selectedType) {
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
        e.preventDefault();
        const floor = getFloor(activeFloorId);
        if (!floor) return;
        const column = (floor.columns || []).find(c => c.id === selectedId);
        if (!column) return;
        const duplicate = duplicateColumn(column);
        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
        return;
      }

      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
        const floor = getFloor(activeFloorId);
        if (!floor) return;
        if (selectedType === 'wall') {
          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
        } else if (selectedType === 'door') {
          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
        } else if (selectedType === 'window') {
          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
        } else if (selectedType === 'column') {
          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
        } else if (selectedType === 'beam') {
          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
        } else if (selectedType === 'stair') {
          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
        } else if (selectedType === 'annotation') {
          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
        } else if (selectedType === 'slab') {
          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId });
        } else if (selectedType === 'sectionCut') {
          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId });
        } else if (selectedType === 'room') {
          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
        }
        editorDispatch({ type: 'DESELECT' });
      }
    },

    getCursor(toolState) {
      if (toolState.dragging) return 'grabbing';
      return 'default';
    },
  };
}

import { columnOutline } from '@/geometry/columnGeometry';
import { getBeamRenderData } from '@/geometry/beamGeometry';
import { getStairRenderData } from '@/geometry/stairGeometry';
import { getSlabRenderData } from '@/geometry/slabGeometry';
import { getWallRenderData } from '@/geometry/wallColumnGeometry';
import { getManualAnnotationFigure } from '@/annotations/scene';
import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';

const HANDLE_SIZE = 8; // px, will use vectorEffect

function WallSelection({ wall, columns, zoom }) {
  const outline = getWallRenderData(wall, columns || []).outline;
  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
  const handleR = HANDLE_SIZE / zoom;

  return (
    <g>
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
      {/* Endpoint handles */}
      <rect
        data-handle="start"
        x={wall.start.x - handleR / 2}
        y={wall.start.y - handleR / 2}
        width={handleR}
        height={handleR}
        fill="white"
        stroke="var(--color-selection)"
        strokeWidth={2}
        vectorEffect="non-scaling-stroke"
        style={{ cursor: 'move' }}
      />
      <rect
        data-handle="end"
        x={wall.end.x - handleR / 2}
        y={wall.end.y - handleR / 2}
        width={handleR}
        height={handleR}
        fill="white"
        stroke="var(--color-selection)"
        strokeWidth={2}
        vectorEffect="non-scaling-stroke"
        style={{ cursor: 'move' }}
      />
    </g>
  );
}

export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
  if (!selectedId || !floor) return null;

  if (selectedType === 'slab') {
    const slab = floor.slab;
    const renderData = slab?.id === selectedId ? getSlabRenderData(slab) : null;
    if (!renderData) return null;

    const handleR = HANDLE_SIZE / zoom;
    return (
      <g>
        <polygon
          points={renderData.points}
          fill="var(--color-selection-fill)"
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
        {renderData.outline.map((point, index) => (
          <rect
            key={`${point.x}-${point.y}-${index}`}
            data-handle="slab-vertex"
            data-index={index}
            x={point.x - handleR / 2}
            y={point.y - handleR / 2}
            width={handleR}
            height={handleR}
            fill="white"
            stroke="var(--color-selection)"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
            style={{ cursor: 'move' }}
          />
        ))}
      </g>
    );
  }

  if (selectedType === 'wall') {
    const wall = floor.walls.find(w => w.id === selectedId);
    if (!wall) return null;
    return <WallSelection wall={wall} columns={floor.columns || []} zoom={zoom} />;
  }

  if (selectedType === 'sectionCut') {
    const sectionCut = floor.sectionCut?.id === selectedId ? floor.sectionCut : null;
    const renderData = getSectionCutRenderData(sectionCut);
    if (!renderData) return null;
    const handleR = HANDLE_SIZE / zoom;

    return (
      <g>
        <line
          x1={renderData.line.start.x}
          y1={renderData.line.start.y}
          x2={renderData.line.end.x}
          y2={renderData.line.end.y}
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
        <rect
          data-handle="start"
          x={sectionCut.startPoint.x - handleR / 2}
          y={sectionCut.startPoint.y - handleR / 2}
          width={handleR}
          height={handleR}
          fill="white"
          stroke="var(--color-selection)"
          strokeWidth={2}
          vectorEffect="non-scaling-stroke"
          style={{ cursor: 'move' }}
        />
        <rect
          data-handle="end"
          x={sectionCut.endPoint.x - handleR / 2}
          y={sectionCut.endPoint.y - handleR / 2}
          width={handleR}
          height={handleR}
          fill="white"
          stroke="var(--color-selection)"
          strokeWidth={2}
          vectorEffect="non-scaling-stroke"
          style={{ cursor: 'move' }}
        />
      </g>
    );
  }

  if (selectedType === 'annotation') {
    const figure = getManualAnnotationFigure(floor, selectedId);
    if (!figure) return null;
    return (
      <g>
        {figure.extensionLines.map((line, index) => (
          <line
            key={`annotation-ext-${index}`}
            x1={line.start.x}
            y1={line.start.y}
            x2={line.end.x}
            y2={line.end.y}
            stroke="var(--color-selection)"
            strokeWidth={2}
            strokeDasharray="6 3"
            vectorEffect="non-scaling-stroke"
          />
        ))}
        <line
          x1={figure.lineStart.x}
          y1={figure.lineStart.y}
          x2={figure.lineEnd.x}
          y2={figure.lineEnd.y}
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
      </g>
    );
  }

  if (selectedType === 'door') {
    const door = floor.doors.find(d => d.id === selectedId);
    if (!door) return null;
    const wall = floor.walls.find(w => w.id === door.wallId);
    if (!wall) return null;
    // Highlight parent wall subtly
    const outline = getWallRenderData(wall, floor.columns || []).outline;
    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="none"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'beam') {
    const beam = (floor.beams || []).find(b => b.id === selectedId);
    if (!beam) return null;
    const renderData = getBeamRenderData(beam, floor.columns || []);
    if (!renderData) return null;
    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'stair') {
    const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
    if (!stair) return null;
    const renderData = getStairRenderData(stair);
    if (!renderData) return null;
    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'window') {
    const win = floor.windows.find(w => w.id === selectedId);
    if (!win) return null;
    const wall = floor.walls.find(w => w.id === win.wallId);
    if (!wall) return null;
    const outline = getWallRenderData(wall, floor.columns || []).outline;
    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="none"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'column') {
    const column = (floor.columns || []).find(c => c.id === selectedId);
    if (!column) return null;
    const outline = columnOutline(column);
    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
    const handleR = HANDLE_SIZE / zoom;
    return (
      <g>
        <polygon
          points={points}
          fill="var(--color-selection-fill)"
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
        {outline.map((p, i) => (
          <rect
            key={i}
            x={p.x - handleR / 2}
            y={p.y - handleR / 2}
            width={handleR}
            height={handleR}
            fill="white"
            stroke="var(--color-selection)"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
            style={{ cursor: 'move' }}
          />
        ))}
      </g>
    );
  }

  if (selectedType === 'room') {
    const room = floor.rooms.find(r => r.id === selectedId);
    if (!room?.points?.length) return null;
    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="none"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  return null;
}

