 97→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 98→  return {
 99→    onMouseDown(modelPos, e, toolState) {
100→      if (e.button !== 0) return;
101→
102→      const floor = getFloor(activeFloorId);
103→      if (!floor) return;
104→
105→      // Check if clicking a handle
106→      const target = e.target;
107→      if (target.dataset.handle) {
108→        editorDispatch({
109→          type: 'UPDATE_TOOL_STATE',
110→          payload: {
111→            dragging: true,
112→            dragType: 'handle',
113→            handle: target.dataset.handle,
114→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
115→            startPos: modelPos,
116→          },
117→        });
118→        return;
119→      }
120→
121→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
122→      if (hit) {
123→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
124→        const draggableTypes = new Set(['wall', 'column', 'door', 'window', 'stair', 'sectionCut']);
125→        if (!draggableTypes.has(hit.type)) return;
126→        editorDispatch({
127→          type: 'UPDATE_TOOL_STATE',
128→          payload: {
129→            dragging: true,
130→            dragType: 'move',
131→            startPos: modelPos,
132→            originalPos: modelPos,
133→          },
134→        });
135→      } else {
136→        editorDispatch({ type: 'DESELECT' });
137→      }
138→    },
139→
140→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
141→      if (!toolState.dragging || !selectedId) return;
142→
143→      const floor = getFloor(activeFloorId);
144→      if (!floor) return;
145→      const dx = modelPos.x - toolState.startPos.x;
146→      const dy = modelPos.y - toolState.startPos.y;
147→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
148→
149→      if (selectedType === 'wall') {
150→        const wall = floor.walls.find(w => w.id === selectedId);
151→        if (!wall) return;
152→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
153→
154→        if (toolState.dragType === 'handle') {
155→          const handle = toolState.handle;
156→          const oppositeKey = handle === 'start' ? 'end' : 'start';
157→          const oppositePoint = resolved[oppositeKey];
158→          let nextPoint = modelPos;
159→          let nextAttachment = null;
160→
161→          if (e.shiftKey) {
162→            const dx = modelPos.x - oppositePoint.x;
163→            const dy = modelPos.y - oppositePoint.y;
164→            const angle = Math.atan2(dy, dx);
165→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
166→            const len = Math.sqrt(dx * dx + dy * dy);
167→            nextPoint = {
168→              x: oppositePoint.x + Math.cos(snapAngle) * len,
169→              y: oppositePoint.y + Math.sin(snapAngle) * len,
170→            };
171→          } else if (snapEnabled) {
172→            const snapResult = snapWallEndpoint(modelPos, {
173→              walls: floor.walls,
174→              columns: floor.columns || [],
175→              snapDist: snapDistModel,
176→              otherPoint: oppositePoint,
177→              ignoreWallId: wall.id,
178→            });
179→            if (snapResult) {
180→              nextPoint = snapResult.point;
181→              nextAttachment = snapResult.attachment;
182→            }
183→          }
184→
185→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
186→
187→          dispatch({
188→            type: 'WALL_UPDATE',
189→            floorId: activeFloorId,
190→            wall: {
191→              id: wall.id,
192→              [handle]: nextPoint,
193→              [`${handle}Attachment`]: nextAttachment,
194→            },
195→          });
196→        } else {
197→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
198→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
199→          let startAttachment = null;
200→          let endAttachment = null;
201→
202→          if (snapEnabled) {
203→            const startSnap = snapWallEndpoint(nextStart, {
204→              walls: floor.walls,
205→              columns: floor.columns || [],
206→              snapDist: snapDistModel,
207→              otherPoint: nextEnd,
208→              ignoreWallId: wall.id,
209→            });
210→            if (startSnap) {
211→              nextStart = startSnap.point;
212→              startAttachment = startSnap.attachment;
213→            }
214→
215→            const endSnap = snapWallEndpoint(nextEnd, {
216→              walls: floor.walls,
217→              columns: floor.columns || [],
218→              snapDist: snapDistModel,
219→              otherPoint: nextStart,
220→              ignoreWallId: wall.id,
221→            });
222→            if (endSnap) {
223→              nextEnd = endSnap.point;
224→              endAttachment = endSnap.attachment;
225→            }
226→          }
227→
228→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
229→
230→          dispatch({
231→            type: 'WALL_UPDATE',
232→            floorId: activeFloorId,
233→            wall: {
234→              id: wall.id,
235→              start: nextStart,
236→              end: nextEnd,
237→              startAttachment,
238→              endAttachment,
239→            },
240→          });
241→        }
242→        editorDispatch({
243→          type: 'UPDATE_TOOL_STATE',
244→          payload: { startPos: modelPos },
245→        });
246→      } else if (selectedType === 'column') {
247→        const col = (floor.columns || []).find(c => c.id === selectedId);
248→        if (!col) return;
249→        dispatch({
250→          type: 'COLUMN_UPDATE',
251→          floorId: activeFloorId,
252→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
253→        });
254→        editorDispatch({
255→          type: 'UPDATE_TOOL_STATE',
256→          payload: { startPos: modelPos },
257→        });
258→      } else if (selectedType === 'sectionCut') {
259→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
260→        if (!sectionCut) return;
261→
262→        if (toolState.dragType === 'handle') {
263→          const handle = toolState.handle;
264→          const nextSectionCut = handle === 'start'
265→            ? { ...sectionCut, startPoint: modelPos }
266→            : { ...sectionCut, endPoint: modelPos };
267→
268→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
269→
270→          dispatch({
271→            type: 'SECTION_UPDATE',
272→            floorId: activeFloorId,
273→            sectionCut: nextSectionCut,
274→          });
275→        } else {
276→          dispatch({
277→            type: 'SECTION_UPDATE',
278→            floorId: activeFloorId,
279→            sectionCut: {
280→              id: sectionCut.id,
281→              startPoint: {
282→                x: sectionCut.startPoint.x + dx,
283→                y: sectionCut.startPoint.y + dy,
284→              },
285→              endPoint: {
286→                x: sectionCut.endPoint.x + dx,
287→                y: sectionCut.endPoint.y + dy,
288→              },
289→            },
290→          });
291→          editorDispatch({
292→            type: 'UPDATE_TOOL_STATE',
293→            payload: { startPos: modelPos },
294→          });
295→        }
296→      } else if (selectedType === 'beam') {
297→        return;
298→      } else if (selectedType === 'stair') {
299→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
300→        if (!stair) return;
301→        dispatch({
302→          type: 'STAIR_UPDATE',
303→          floorId: activeFloorId,
304→          stair: {
305→            id: stair.id,
306→            startPoint: {
307→              x: stair.startPoint.x + dx,
308→              y: stair.startPoint.y + dy,
309→            },
310→          },
311→        });
312→        editorDispatch({
313→          type: 'UPDATE_TOOL_STATE',
314→          payload: { startPos: modelPos },
315→        });
316→      } else if (selectedType === 'slab') {
317→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
318→          return;
319→        }
320→        if (!floor.slab || floor.slab.id !== selectedId) return;
321→
322→        const boundaryPoints = floor.slab.boundaryPoints.map((point, index) => (
323→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
324→        ));
325→
326→        dispatch({
327→          type: 'SLAB_UPDATE',
328→          floorId: activeFloorId,
329→          slab: {
330→            id: floor.slab.id,
331→            boundaryPoints,
332→          },
333→        });
334→        editorDispatch({
335→          type: 'UPDATE_TOOL_STATE',
336→          payload: { startPos: modelPos },
337→        });
338→      } else if (selectedType === 'door' || selectedType === 'window') {
339→        // Slide along parent wall
340→        const items = selectedType === 'door' ? floor.doors : floor.windows;
341→        const item = items.find(i => i.id === selectedId);
