            ))}
          </Section>

          <Section
            title="Doors"
            count={floor.doors.length}
            collapsed={collapsedSections.doors}
            onToggle={() => toggleSection('doors')}
          >
            {floor.doors.map(d => (
              <div
                key={d.id}
                className={`${styles.item} ${selectedId === d.id ? styles.itemSelected : ''}`}
                onClick={() => selectObject(d.id, 'door')}
              >
