  1→import { getSheetDisplayLabel } from '@/domain/sheetModels';
  2→import { getPaperPreset } from './paper';
  3→import { getViewportSourceLabel, resolveSheetViewportSource } from './sources';
  4→
  5→const SHEET_MARGIN = 12;
  6→const TITLE_BLOCK_HEIGHT = 32;
  7→const CONTENT_PADDING = 4;
  8→
  9→function clamp(value, min, max) {
 10→  return Math.max(min, Math.min(max, value));
 11→}
 12→
 13→function resolveViewportScale(viewport) {
 14→  return Math.max(1, viewport.scale || 100);
 15→}
 16→
 17→function buildTitleBlock(project, sheet, paper) {
 18→  const titleBlockWidth = Math.min(130, paper.width * 0.42);
 19→  const x = paper.width - SHEET_MARGIN - titleBlockWidth;
 20→  const y = paper.height - SHEET_MARGIN - TITLE_BLOCK_HEIGHT;
 21→
 22→  return {
 23→    x,
 24→    y,
 25→    width: titleBlockWidth,
 26→    height: TITLE_BLOCK_HEIGHT,
 27→    rows: [
 28→      { label: 'Drawing', value: sheet.drawingName || getSheetDisplayLabel(sheet) },
 29→      { label: 'Project', value: sheet.projectNameOverride || project.name || 'Untitled Project' },
 30→      { label: 'Scale', value: sheet.scaleLabel || 'As noted' },
 31→    ],
 32→  };
 33→}
 34→
 35→function resolveViewportTitle(viewport, source) {
 36→  return viewport.title?.trim() || source.title || getViewportSourceLabel(viewport.sourceView);
 37→}
 38→
 39→function buildViewportFrame(viewport, source) {
 40→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 41→  const scale = 1 / resolveViewportScale(viewport);
 42→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 43→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 44→  const innerWidth = Math.max(10, viewport.width - CONTENT_PADDING * 2);
 45→  const innerHeight = Math.max(10, viewport.height - CONTENT_PADDING * 2);
 46→  const drawnWidth = sourceWidth * scale;
 47→  const drawnHeight = sourceHeight * scale;
 48→
 49→  const translateX = Math.max(0, (innerWidth - drawnWidth) / 2) - bounds.minX * scale;
 50→  const translateY = Math.max(0, (innerHeight - drawnHeight) / 2) - bounds.minY * scale;
 51→
 52→  return {
 53→    ...viewport,
 54→    title: resolveViewportTitle(viewport, source),
 55→    source,
 56→    clipRect: {
 57→      x: viewport.x + CONTENT_PADDING,
 58→      y: viewport.y + CONTENT_PADDING,
 59→      width: innerWidth,
 60→      height: innerHeight,
 61→    },
 62→    contentTransform: {
 63→      translateX,
 64→      translateY,
 65→      scale,
 66→    },
 67→  };
 68→}
 69→
 70→export function buildSheetScene(project, sheet) {
 71→  if (!sheet) return null;
 72→
 73→  const paper = getPaperPreset(sheet.paperSize);
 74→  const titleBlock = buildTitleBlock(project, sheet, paper);
 75→  const contentArea = {
 76→    x: SHEET_MARGIN,
 77→    y: SHEET_MARGIN,
 78→    width: paper.width - SHEET_MARGIN * 2,
 79→    height: paper.height - SHEET_MARGIN * 2,
 80→  };
 81→
 82→  const viewports = (sheet.viewports || []).map((viewport) => (
 83→    buildViewportFrame(viewport, resolveSheetViewportSource(project, viewport))
 84→  ));
 85→
 86→  return {
 87→    paper,
 88→    title: getSheetDisplayLabel(sheet),
 89→    border: {
 90→      x: SHEET_MARGIN,
 91→      y: SHEET_MARGIN,
 92→      width: paper.width - SHEET_MARGIN * 2,
 93→      height: paper.height - SHEET_MARGIN * 2,
 94→    },
 95→    contentArea,
 96→    titleBlock,
 97→    viewports,
 98→  };
 99→}
100→
101→export function fitViewportToSheet(viewport, sheet) {
102→  const paper = getPaperPreset(sheet.paperSize);
103→  const width = clamp(viewport.width, 40, paper.width - SHEET_MARGIN * 2);
104→  const height = clamp(viewport.height, 30, paper.height - SHEET_MARGIN * 2 - TITLE_BLOCK_HEIGHT);
105→  const maxX = paper.width - SHEET_MARGIN - width;
106→  const maxY = paper.height - SHEET_MARGIN - height;
107→
108→  return {
109→    ...viewport,
110→    width,
111→    height,
112→    x: clamp(viewport.x, SHEET_MARGIN, maxX),
113→    y: clamp(viewport.y, SHEET_MARGIN, maxY),
114→  };
115→}
116→
117→export function getDefaultViewportRect(sheet, source, scale = 100) {
118→  const paper = getPaperPreset(sheet.paperSize);
